 77→    internal fun release() {
 78→        /*
 79→         * Called from `releaseInterceptedContinuation`, can be concurrent with
 80→         * the code in `getResult` right after `trySuspend` returned `true`, so we have
 81→         * to wait for a release here.
 82→         */
 83→        awaitReusability()
